Here are the public test cases for feature1_2_user_condition:
{
  "description": "User condition: passes when the current request's user has the expected username. Requires request context; when the request is absent the evaluation reports a normalized missing-required-argument error naming the missing argument and the condition.",
  "cases": [
    {
      "input": {
        "op": "check_condition",
        "condition": "user",
        "value": "testuser",
        "request": {
          "username": "testuser"
        }
      },
      "expected_output": "result=true\n"
    },
    {
      "input": {
        "op": "check_condition",
        "condition": "user",
        "value": "testuser"
      },
      "expected_output": "error=missing_required_argument\nargument=request\ncondition=user\n"
    }
  ]
}

